(()=>{"use strict";(()=>{const e=document.querySelectorAll(".section"),t=document.querySelectorAll(".docs-side-nav__item--link");window.onscroll=()=>{let o="";e.forEach((e=>{const t=e.offsetTop;scrollY>=t+450&&(o=e.getAttribute("id"))})),t.forEach((e=>{e.classList.remove("active"),e.classList.contains(o)&&e.classList.add("active")}))};const o=document.querySelectorAll(".docs-side-nav__item--link");o.forEach((e=>{e.addEventListener("click",(()=>{o.forEach((e=>{e.classList.remove("active")})),e.classList.add("active")}))}))})(),(()=>{const e={trigger:document.querySelector(".mobile-tav-trigger"),menu:document.querySelector(".theme-main-menu"),body:document.querySelector("body")};e.trigger.addEventListener("click",(()=>{e.menu.classList.toggle("open"),e.body.style.position="fixed"===e.body.style.position?"":"fixed"}))})()})();